#!/usr/bin/env python3
import base64, os, sys
if not os.path.isfile("App.js"): sys.exit("Run from BatKnock root")

with open("app.json", "wb") as f: f.write(base64.b64decode(""))
print("OK app.json")

with open("App.js", "wb") as f: f.write(base64.b64decode(""))
print("OK App.js")

os.makedirs("screens", exist_ok=True)
with open("screens/HomeScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/HomeScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/BatProfileScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/BatProfileScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/PrepTimerScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/PrepTimerScreen.js")

print()
print("Install notifications package:")
print("  npx expo install expo-notifications")
print()
print("Then run: npx expo start --clear --lan")
